// Normalise all incoming error events to a unified schema.
// Handles: webhook payloads, log API responses, Sentry, Datadog.

const items = $input.all();
const normalised = [];

for (const item of items) {
  const raw = item.json;

  // Detect source type and map fields
  let event = {};

  if (raw.exception || raw.platform) {
    // Sentry format
    event = {
      source: 'sentry',
      error_id: raw.id || crypto.randomUUID(),
      timestamp: raw.dateCreated || new Date().toISOString(),
      service: raw.project?.name || raw.culprit || 'unknown',
      environment: raw.tags?.find(t => t[0]==='environment')?.[1] || 'production',
      message: raw.title || raw.message || 'Unknown error',
      stack_trace: raw.exception?.values?.[0]?.stacktrace?.frames?.map(f => `${f.filename}:${f.lineno}`).join('\n') || '',
      error_type: raw.exception?.values?.[0]?.type || 'GenericError',
      level: raw.level || 'error',
      url: raw.permalink || '',
      metadata: { project: raw.project?.slug, count: raw.count }
    };
  } else if (raw.series || raw.query) {
    // Datadog format
    event = {
      source: 'datadog',
      error_id: raw.jobId || crypto.randomUUID(),
      timestamp: new Date().toISOString(),
      service: raw.tags?.service || 'unknown',
      environment: raw.tags?.env || 'production',
      message: raw.title || 'Metric anomaly detected',
      stack_trace: '',
      error_type: 'MetricAnomaly',
      level: raw.priority || 'error',
      url: raw.url || '',
      metadata: { query: raw.query, value: raw.series?.[0]?.pointlist?.slice(-1)[0] }
    };
  } else if (raw.alerts || raw.incident) {
    // PagerDuty format
    event = {
      source: 'pagerduty',
      error_id: raw.incident?.id || crypto.randomUUID(),
      timestamp: raw.incident?.created_at || new Date().toISOString(),
      service: raw.incident?.service?.summary || 'unknown',
      environment: 'production',
      message: raw.incident?.title || 'PagerDuty incident',
      stack_trace: '',
      error_type: 'Incident',
      level: raw.incident?.urgency === 'high' ? 'critical' : 'error',
      url: raw.incident?.html_url || '',
      metadata: { status: raw.incident?.status }
    };
  } else {
    // Generic webhook / custom app format
    event = {
      source: raw.source || 'webhook',
      error_id: raw.error_id || raw.id || crypto.randomUUID(),
      timestamp: raw.timestamp || raw.time || new Date().toISOString(),
      service: raw.service || raw.app || raw.application || 'unknown',
      environment: raw.environment || raw.env || 'production',
      message: raw.message || raw.error || raw.description || 'Unknown error',
      stack_trace: raw.stack_trace || raw.stacktrace || raw.stack || '',
      error_type: raw.error_type || raw.type || raw.name || 'GenericError',
      level: raw.level || raw.severity || 'error',
      url: raw.url || raw.link || '',
      metadata: raw.metadata || raw.extra || {}
    };
  }

  // Deduplicate: skip if same error_id seen in last 10 min
  // (In production, use Redis or n8n's built-in cache)
  normalised.push({ json: event });
}

return normalised;

