// Parse AI response and merge with original event
const items = $input.all();
const results = [];

for (const item of items) {
  let aiRaw = item.json.message?.content || item.json.choices?.[0]?.message?.content || item.json.text || '{}';

  // Strip markdown fences if present
  aiRaw = aiRaw.replace(/```json\n?|```\n?/g, '').trim();

  let classification;
  try {
    classification = JSON.parse(aiRaw);
  } catch(e) {
    classification = {
      severity: 'medium',
      severity_score: 50,
      error_category: 'application',
      root_cause_hypothesis: 'Parse error - manual review required',
      confidence: 0,
      needs_human_review: true,
      remediation_actions: [{ action: 'investigate_only', confidence: 1.0, safe_to_automate: false, rationale: 'AI parse failed' }],
      notify_channels: ['slack-incidents'],
      jira_priority: 'High',
      jira_labels: ['ai-parse-error'],
      jira_summary: 'Classification failed - manual review',
      jira_description: 'AI classification failed to parse. Raw response: ' + aiRaw
    };
  }

  // Pull original event from previous node context
  const originalEvent = $('Code: Normalise Schema').item.json;

  results.push({
    json: {
      ...originalEvent,
      classification,
      // Convenience top-level fields for routing
      severity: classification.severity,
      confidence: classification.confidence,
      needs_human_review: classification.needs_human_review,
      auto_remediation_available: classification.remediation_actions?.some(a => a.safe_to_automate && a.confidence > 0.7),
      processed_at: new Date().toISOString()
    }
  });
}

return results;

// Determine which remediation action to execute
const item = $input.first().json;
const actions = item.classification.remediation_actions || [];

// Pick highest confidence safe action
const safeActions = actions
  .filter(a => a.safe_to_automate && a.action !== 'investigate_only')
  .sort((a, b) => b.confidence - a.confidence);

const chosenAction = safeActions[0] || null;

return [{
  json: {
    ...item,
    chosen_action: chosenAction,
    will_attempt_remediation: !!chosenAction && item.confidence >= 0.7 && !item.needs_human_review
  }
}];

// Execute the chosen remediation action via HTTP calls
// In production, replace URLs with your actual infrastructure endpoints

const item = $input.first().json;
const action = item.chosen_action;
const service = item.service;
const params = action.parameters || {};

console.log(`Executing remediation: ${action.action} for service: ${service}`);

const actionMap = {
  restart_service: {
    url: `${$env.INFRA_API_URL}/services/${service}/restart`,
    method: 'POST',
    body: { reason: 'auto-remediation', triggered_by: 'n8n-monitor', error_id: item.error_id }
  },
  scale_up: {
    url: `${$env.INFRA_API_URL}/services/${service}/scale`,
    method: 'PATCH',
    body: { replicas: (params.target_replicas || 2), reason: 'auto-scale-remediation' }
  },
  flush_cache: {
    url: `${$env.INFRA_API_URL}/cache/${params.cache_name || service}/flush`,
    method: 'DELETE',
    body: { triggered_by: 'n8n-monitor', error_id: item.error_id }
  },
  clear_queue: {
    url: `${$env.QUEUE_API_URL}/queues/${params.queue_name || service}/purge`,
    method: 'POST',
    body: { triggered_by: 'n8n-monitor', error_id: item.error_id }
  }
};

const actionConfig = actionMap[action.action];
if (!actionConfig) {
  return [{ json: { ...item, remediation_attempted: false, remediation_result: 'unsupported_action', remediation_skipped_reason: action.action } }];
}

// Return config for the HTTP node that follows
return [{
  json: {
    ...item,
    remediation_attempted: true,
    http_config: actionConfig,
    remediation_start_time: new Date().toISOString()
  }
}];

